#!/bin/bash

source ${HOME}/miniconda3/etc/profile.d/conda.sh
conda activate rocprofiler-compute

# ROCM_PATH=/opt/rocm-7.1.0
ROCM_PATH=/opt/rocm-6.4.1
ROCPROF_COMPUTE=${ROCM_PATH}/bin/rocprof-compute

# Encountered errors when LD_LIBRARY_PATH is not set:
# - symbol lookup error: libamdhip64.so
export LD_LIBRARY_PATH=${LD_LIBRARY_PATH}:${ROCM_PATH}/lib 

BASE_DIR=${HOME}/workspace/ici-workspace/ici/benchmarks/mi300x_amo_hol_blocking
BIN_DIR=${BASE_DIR}/bin

# set workload dir to current directory's workloads
WORKLOAD_DIR=workloads

# List of all executables generated by the Makefile
# amo_hol_blocking $(tpb) $(k1 max tpb) $(k2 max tpb)
TARGETS=(
  "amo_hol_blocking_128_128_128"
  "amo_hol_blocking_256_128_128"
  "amo_hol_blocking_256_128_256"
  "amo_hol_blocking_256_256_128"
  "amo_hol_blocking_256_256_256"
  "amo_hol_blocking_512_128_128"
  "amo_hol_blocking_512_128_256"
  "amo_hol_blocking_512_128_512"
  "amo_hol_blocking_512_256_128"
  "amo_hol_blocking_512_256_256"
  "amo_hol_blocking_512_256_512"
  "amo_hol_blocking_512_512_128"
  "amo_hol_blocking_512_512_256"
  "amo_hol_blocking_512_512_512"
)

# Loop through each target and run profiling and analysis
for TARGET in "${TARGETS[@]}"; do
  echo "Profiling and analyzing ${TARGET}..."
  ${ROCPROF_COMPUTE} profile -n ${TARGET} -- ${BIN_DIR}/${TARGET}
  ${ROCPROF_COMPUTE} analyze -p ${WORKLOAD_DIR}/${TARGET}/MI300X_A1/ -k 0 > ${WORKLOAD_DIR}/${TARGET}/MI300X_A1/analyze.out
done